/**
 * 章节分析面板
 * 提供：自动摘要、人物出场统计、对话分析、情节点提取
 */

import { useState } from 'react'
import {
  Button,
  Space,
  Card,
  message,
  Spin,
  Tabs,
  Statistic,
  Row,
  Col,
  Tag,
  List,
  Progress,
  Alert,
  Divider,
} from 'antd'
import {
  FileTextOutlined,
  TeamOutlined,
  MessageOutlined,
  ThunderboltOutlined,
  ReloadOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'

interface AnalysisPanelProps {
  chapterContent: string
  chapterPath: string | null
  projectRoot: string | null
}

interface CharacterAppearance {
  name: string
  count: number
  paragraphs: number
}

interface DialogueInfo {
  speaker: string
  content: string
  position: number
}

interface PlotPoint {
  order: number
  event: string
  description: string
}

const AnalysisPanel: React.FC<AnalysisPanelProps> = ({
  chapterContent,
  chapterPath,
  projectRoot,
}) => {
  const [analyzing, setAnalyzing] = useState(false)
  const [activeTab, setActiveTab] = useState<string>('summary')

  // 摘要
  const [summary, setSummary] = useState('')
  const [summaryLoading, setSummaryLoading] = useState(false)

  // 人物统计
  const [characters, setCharacters] = useState<CharacterAppearance[]>([])
  const [dialogues, setDialogues] = useState<DialogueInfo[]>([])
  const [dialogueRatio, setDialogueRatio] = useState(0)
  const [characterStatsLoading, setCharacterStatsLoading] = useState(false)

  // 情节点
  const [plotPoints, setPlotPoints] = useState<PlotPoint[]>([])
  const [plotPointsLoading, setPlotPointsLoading] = useState(false)

  // 生成自动摘要
  const handleGenerateSummary = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setSummaryLoading(true)
    try {
      const fullPrompt = `请为以下小说章节生成200字左右的摘要，概括核心情节、人物关系变化和关键事件：

${chapterContent.slice(0, 3000)}

摘要（200字左右）：` as string

      const result = await aiModelService.call('summary', fullPrompt, {
        systemPrompt: '你是一个小说摘要专家。请用简洁精炼的语言概括章节核心内容。',
      })

      if (result.success && result.content) {
        setSummary(result.content)
        setActiveTab('summary')
      } else {
        message.error(result.error || '摘要生成失败')
      }
    } catch (error) {
      message.error('摘要生成失败')
    } finally {
      setSummaryLoading(false)
    }
  }

  // 人物出场统计
  const handleCharacterStats = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }
    setCharacterStatsLoading(true)
    try {
      // 读取角色列表
      let characterNames: string[] = []
      const charactersDir = `${projectRoot}/characters`
      const charsExistsResult = await window.electronAPI.exists(charactersDir)
      if (!charsExistsResult.success || !charsExistsResult.exists) {
        setCharacters([])
        setCharacterStatsLoading(false)
        return
      }
      const entriesResult = await window.electronAPI.readdir(charactersDir)
      if (!entriesResult.success) { console.error('读取characters目录失败:', entriesResult.error); setCharacters([]); setCharacterStatsLoading(false); return; }
      const entries = entriesResult.data || []
      const yamlFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )
      for (const file of yamlFiles) {
        const result = await window.electronAPI.yaml.read(`${charactersDir}/${file.name}`)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          if (data.name && typeof data.name === 'string') {
            characterNames.push(data.name)
          }
        }
      }

      // 统计章节中出现的人物
      const content = chapterContent
      const charAppearances: Record<string, { count: number; paragraphs: Set<number> }> = {}

      // 按段落分割
      const paragraphs = content.split(/\n\n+/)

      paragraphs.forEach((para, paraIdx) => {
        for (const name of characterNames) {
          if (para.includes(name)) {
            if (!charAppearances[name]) {
              charAppearances[name] = { count: 0, paragraphs: new Set() }
            }
            charAppearances[name].count++
            charAppearances[name].paragraphs.add(paraIdx)
          }
        }
      })

      const sortedChars = Object.entries(charAppearances)
        .map(([name, stats]) => ({
          name,
          count: stats.count,
          paragraphs: stats.paragraphs.size,
        }))
        .sort((a, b) => b.count - a.count)

      setCharacters(sortedChars)

      // 提取对话
      const dialogueRegex = /[""''『』]([^""''『』]+)[""''『』]/g
      const extractedDialogues: DialogueInfo[] = []
      let match
      let pos = 0
      while ((match = dialogueRegex.exec(content)) !== null) {
        extractedDialogues.push({
          speaker: '',
          content: match[1],
          position: match.index,
        })
        pos++
        if (pos > 50) break
      }

      // 尝试识别说话者（简化版：找引号前的名字）
      const speakerRegex = /([A-Za-z\u4e00-\u9fa5]{2,4})[""'']/
      for (const d of extractedDialogues) {
        const beforeContent = content.slice(Math.max(0, d.position - 30), d.position)
        const speakerMatch = beforeContent.match(speakerRegex)
        if (speakerMatch) {
          d.speaker = speakerMatch[1]
        }
      }

      setDialogues(extractedDialogues.slice(0, 20))

      // 计算对话占比
      const totalChars = content.replace(/\s/g, '').length
      const dialogueChars = extractedDialogues.reduce((sum, d) => sum + d.content.length, 0)
      setDialogueRatio(totalChars > 0 ? (dialogueChars / totalChars) * 100 : 0)

      setActiveTab('characters')
    } catch (error) {
      message.error('统计分析失败')
    } finally {
      setCharacterStatsLoading(false)
    }
  }

  // 情节点提取
  const handlePlotPoints = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setPlotPointsLoading(true)
    try {
      const fullPrompt = `请分析以下小说章节，提取3-5个关键情节点，按时间顺序列出：

${chapterContent.slice(0, 3000)}

情节点列表（格式）：
1. [事件名称] - 简要描述
2. [事件名称] - 简要描述
...` as string

      const result = await aiModelService.call('summary', fullPrompt, {
        systemPrompt: '你是小说情节分析专家。请按时间顺序列出章节的关键事件。',
      })

      if (result.success && result.content) {
        // 解析情节点
        const lines = result.content.split('\n').filter(l => l.trim())
        const points: PlotPoint[] = []
        let order = 1
        for (const line of lines) {
          const match = line.match(/^\d+[.、]\s*(\[.+?\])?\s*(.+)/)
          if (match) {
            points.push({
              order: order++,
              event: match[1] || `情节点${order - 1}`,
              description: match[2].trim(),
            })
          }
        }
        if (points.length === 0) {
          points.push({ order: 1, event: '主要情节点', description: result.content })
        }
        setPlotPoints(points)
        setActiveTab('plotpoints')
      } else {
        message.error(result.error || '情节点提取失败')
      }
    } catch (error) {
      message.error('情节点提取失败')
    } finally {
      setPlotPointsLoading(false)
    }
  }

  // 快速分析（一次性生成所有）
  const handleFullAnalysis = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setAnalyzing(true)
    try {
      await Promise.all([
        handleGenerateSummary(),
        handleCharacterStats(),
        handlePlotPoints(),
      ])
    } finally {
      setAnalyzing(false)
    }
  }

  if (!chapterContent) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先选择章节
      </div>
    )
  }

  const totalChars = chapterContent.replace(/\s/g, '').length
  const wordCount = chapterContent.length

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ marginBottom: 10 }}>
          <span style={{ fontSize: 13, fontWeight: 500 }}>📊 章节分析</span>
        </div>

        {/* 基础统计 */}
        <Row gutter={8} style={{ marginBottom: 10 }}>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>字数</span>}
              value={wordCount}
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>字符</span>}
              value={totalChars}
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>对话占比</span>}
              value={dialogueRatio.toFixed(1)}
              suffix="%"
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
        </Row>

        {/* 分析按钮 */}
        <Space wrap style={{ marginBottom: 8 }}>
          <Button
            size="small"
            icon={<FileTextOutlined />}
            onClick={handleGenerateSummary}
            loading={summaryLoading}
          >
            生成摘要
          </Button>
          <Button
            size="small"
            icon={<TeamOutlined />}
            onClick={handleCharacterStats}
            loading={characterStatsLoading}
          >
            人物统计
          </Button>
          <Button
            size="small"
            icon={<ThunderboltOutlined />}
            onClick={handlePlotPoints}
            loading={plotPointsLoading}
          >
            情节点
          </Button>
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={handleFullAnalysis}
            loading={analyzing}
          >
            全部分析
          </Button>
        </Space>
      </div>

      {/* 分析结果 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        <Tabs
          activeKey={activeTab}
          onChange={setActiveTab}
          size="small"
          items={[
            {
              key: 'summary',
              label: <span>📝 摘要</span>,
              children: (
                <div>
                  {summaryLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="生成摘要中..." />
                    </div>
                  ) : summary ? (
                    <Card size="small" style={{ whiteSpace: 'pre-wrap' }}>
                      {summary}
                    </Card>
                  ) : (
                    <Alert
                      message="点击「生成摘要」获取本章200字摘要"
                      type="info"
                      showIcon
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'characters',
              label: <span>👥 人物</span>,
              children: (
                <div>
                  {characterStatsLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="分析人物中..." />
                    </div>
                  ) : (
                    <>
                      {/* 人物出场 */}
                      {characters.length > 0 ? (
                        <Card
                          size="small"
                          title="人物出场统计"
                          style={{ marginBottom: 12 }}
                        >
                          <List
                            size="small"
                            dataSource={characters.slice(0, 10)}
                            renderItem={(char) => (
                              <List.Item>
                                <div style={{ display: 'flex', justifyContent: 'space-between', width: '100%', alignItems: 'center' }}>
                                  <Tag color="blue">{char.name}</Tag>
                                  <Space size="small">
                                    <span style={{ fontSize: 11, color: '#999' }}>
                                      提及 {char.count} 次 · {char.paragraphs} 段
                                    </span>
                                    <Progress
                                      percent={Math.round((char.count / characters[0].count) * 100)}
                                      size="small"
                                      style={{ width: 60 }}
                                    />
                                  </Space>
                                </div>
                              </List.Item>
                            )}
                          />
                        </Card>
                      ) : (
                        <Alert
                          message="点击「人物统计」分析本章出场人物"
                          type="info"
                          showIcon
                        />
                      )}

                      {/* 对话分析 */}
                      {dialogues.length > 0 && (
                        <Card size="small" title="对话片段">
                          <List
                            size="small"
                            dataSource={dialogues.slice(0, 8)}
                            renderItem={(d) => (
                              <List.Item>
                                <div style={{ width: '100%' }}>
                                  {d.speaker && <Tag color="green" style={{ marginBottom: 4 }}>{d.speaker}</Tag>}
                                  <div style={{ fontSize: 12, fontStyle: 'italic', color: '#666' }}>
                                    「{d.content.slice(0, 60)}{d.content.length > 60 ? '...' : ''}」
                                  </div>
                                </div>
                              </List.Item>
                            )}
                          />
                          <Divider style={{ margin: '8px 0' }} />
                          <div style={{ fontSize: 11, color: '#999' }}>
                            共 {dialogues.length} 段对话，对话占比 {dialogueRatio.toFixed(1)}%
                          </div>
                        </Card>
                      )}
                    </>
                  )}
                </div>
              ),
            },
            {
              key: 'plotpoints',
              label: <span>⚡ 情节点</span>,
              children: (
                <div>
                  {plotPointsLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="提取情节点中..." />
                    </div>
                  ) : plotPoints.length > 0 ? (
                    <Card size="small" title="本章关键情节点">
                      <List
                        size="small"
                        dataSource={plotPoints}
                        renderItem={(point) => (
                          <List.Item>
                            <List.Item.Meta
                              avatar={<div style={{
                                width: 24,
                                height: 24,
                                borderRadius: '50%',
                                background: '#1890ff',
                                color: '#fff',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                fontSize: 12,
                              }}>
                                {point.order}
                              </div>}
                              title={<span>{point.event}</span>}
                              description={<span style={{ fontSize: 12, color: '#666' }}>{point.description}</span>}
                            />
                          </List.Item>
                        )}
                      />
                    </Card>
                  ) : (
                    <Alert
                      message="点击「情节点」提取本章关键事件"
                      type="info"
                      showIcon
                    />
                  )}
                </div>
              ),
            },
          ]}
        />
      </div>
    </div>
  )
}

export default AnalysisPanel

/**
 * 番茄小说创作助手 - 预加载脚本入口
 *
 * 暴露安全的 API 给渲染进程
 * 所有 API 通过 contextBridge 暴露
 */
export type ElectronAPI = {
    openDirectory: () => Promise<string | undefined>;
    readFile: (filePath: string) => Promise<{
        success: boolean;
        content?: string;
        error?: string;
    }>;
    exists: (filePath: string) => Promise<boolean>;
    readdir: (dirPath: string) => Promise<Array<{
        name: string;
        isDirectory: boolean;
        isFile: boolean;
    }>>;
    writeFile: (filePath: string, content: string) => Promise<{
        success: boolean;
        error?: string;
    }>;
    mkdir: (dirPath: string) => Promise<{
        success: boolean;
        error?: string;
    }>;
    unlink: (filePath: string) => Promise<{
        success: boolean;
        error?: string;
    }>;
    rmdir: (dirPath: string, options?: {
        recursive?: boolean;
    }) => Promise<{
        success: boolean;
        error?: string;
    }>;
    remove: (targetPath: string) => Promise<{
        success: boolean;
        error?: string;
    }>;
    deleteFile: (filePath: string) => Promise<{
        success: boolean;
        error?: string;
    }>;
    deleteDirectory: (dirPath: string) => Promise<{
        success: boolean;
        error?: string;
    }>;
    renameFile: (oldPath: string, newPath: string) => Promise<{
        success: boolean;
        error?: string;
    }>;
    openPath: (path: string) => Promise<string>;
    getProjectRoot: () => Promise<string | null>;
    fsWatch: (dirPath?: string) => Promise<{
        success: boolean;
        path?: string;
        error?: string;
    }>;
    fsUnwatch: () => Promise<{
        success: boolean;
        error?: string;
    }>;
    onFsChange: (callback: (data: {
        type: string;
        fileName: string;
        path: string;
    }) => void) => () => void;
    safeStorage: {
        encrypt: (plainText: string) => Promise<{
            success: boolean;
            data?: Buffer;
            error?: string;
        }>;
        decrypt: (encrypted: Buffer) => Promise<{
            success: boolean;
            data?: string;
            error?: string;
        }>;
        isAvailable: () => Promise<{
            success: boolean;
            available?: boolean;
            error?: string;
        }>;
    };
    yaml: {
        read: (filePath: string) => Promise<{
            success: boolean;
            data?: any;
            error?: string;
        }>;
        write: (filePath: string, data: any) => Promise<{
            success: boolean;
            error?: string;
        }>;
    };
    ai: {
        saveApiKey: (service: string, apiKey: string) => Promise<{
            success: boolean;
            error?: string;
        }>;
        isConfigured: (service: string) => Promise<{
            success: boolean;
            configured?: boolean;
            error?: string;
        }>;
        getConfiguredServices: () => Promise<{
            success: boolean;
            services?: string[];
            error?: string;
        }>;
        call: (prompt: string, options?: any) => Promise<{
            success: boolean;
            content?: string;
            error?: string;
        }>;
        stream: (prompt: string, options?: any) => Promise<{
            success: boolean;
            error?: string;
        }>;
        onStreamChunk: (callback: (chunk: {
            content: string;
            done: boolean;
            reasoning?: string;
        }) => void) => () => void;
        onStreamError: (callback: (error: string) => void) => () => void;
        testConnection: (service: string) => Promise<{
            success: boolean;
            result?: boolean;
            error?: string;
        }>;
        saveSetting: (key: string, value: any) => Promise<{
            success: boolean;
            error?: string;
        }>;
        getSetting: (key: string, defaultValue?: any) => Promise<{
            success: boolean;
            value?: any;
            error?: string;
        }>;
    };
    backup: {
        create: () => Promise<{
            success: boolean;
            backupPath?: string;
            error?: string;
        }>;
        list: () => Promise<{
            success: boolean;
            backups?: Array<{
                name: string;
                path: string;
                date: string;
                size: number;
            }>;
            error?: string;
        }>;
        restore: (backupPath: string) => Promise<{
            success: boolean;
            error?: string;
        }>;
        delete: (backupPath: string) => Promise<{
            success: boolean;
            error?: string;
        }>;
    };
};
declare global {
    interface Window {
        electronAPI: ElectronAPI;
    }
}

Now I have the full picture. The actual API types reveal critical mismatches.

---

```
[AnalysisPanel.tsx:89] 🔴P0
exists() 返回类型是 boolean，但代码按 {success, exists} 对象处理

代码片段:
  const charsExistsResult = await window.electronAPI.exists(charactersDir)
  if (!charsExistsResult.success || !charsExistsResult.exists) {

问题: exists() 返回 Promise<boolean>，不是 Promise<{success, exists}>。
      boolean 没有 .success 和 .exists 属性，两者都是 undefined(falsy)，
      导致条件恒为 true，函数永远early return，characters 功能完全失效。

修复建议:
  if (!charsExistsResult) {  // 直接判断布尔值
    setCharacters([])
    setCharacterStatsLoading(false)
    return
  }
```

---

```
[AnalysisPanel.tsx:96] 🔴P0
readdir() 直接返回 Array，不返回 {success, data} 封装对象

代码片段:
  const entriesResult = await window.electronAPI.readdir(charactersDir)
  if (!entriesResult.success) { ... }
  const entries = entriesResult.data || []

问题: 根据类型定义 readdir 返回 Promise<Array<...>>，直接是数组。
      entriesResult.success → undefined (永远falsy)
      entriesResult.data   → undefined (数组没有 .data)
      导致 entries = []，yamlFiles = []，功能静默失效。

修复建议:
  const entries = entriesResult  // 直接使用返回数组
  if (!Array.isArray(entries)) { ...处理错误 }
  const yamlFiles = entries.filter(...)
```

---

```
[AnalysisPanel.tsx:221] 🟠P1
handleFullAnalysis 缺少 try-catch，Promise.all 中任意一个reject会导致未捕获异常

代码片段:
  const handleFullAnalysis = async () => {
    ...
    try {
      await Promise.all([
        handleGenerateSummary(),
        handleCharacterStats(),
        handlePlotPoints(),
      ])
    } finally {
      setAnalyzing(false)
    }
    // 没有 catch
  }

修复建议:
  try {
    await Promise.all([
      handleGenerateSummary(),
      handleCharacterStats(),
      handlePlotPoints(),
    ])
  } catch (error) {
    message.error('全部分析失败')
  } finally {
    setAnalyzing(false)
  }
```

---

```
[AnalysisPanel.tsx:75] 🟠P1
catch 捕获了 error 但没有使用，错误信息丢失，调试困难

代码片段:
  } catch (error) {
    message.error('摘要生成失败')
  }

修复建议:
  } catch (err) {
    console.error('摘要生成失败:', err)
    message.error('摘要生成失败')
  }
```

---

```
[AnalysisPanel.tsx:129] 🟡P2
对话提取正则只匹配了4种引号，但中文小说常用「」且可能混用 "" ''等

代码片段:
  const dialogueRegex = /[""''『』]([^""''『』]+)[""''『』]/g

问题: 如果原文用「...」，正则要求首尾引号必须完全相同字符对，
      「"xxx"」或「对话"xxx」这类混用会匹配失败或只取到部分内容。

修复建议:
  改为 /[""''『』「]([^""''『』」]+)[""''『』」]/g
```

---

**总结：2个P0致命bug导致人物统计完全失效，2个P1/P2次要问题。**
